class Solution {
    public int numberOfSubstrings(String s) {
        int countA = 0, countB = 0, countC = 0;
        int result = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == 'a') {
                countA++;
            } else if (s.charAt(i) == 'b') {
                countB++;
            } else {
                countC++;
            }
            result += countA * countB * countC;
        }
        return result;
    }
}
```
